 * Finds the number of ways to assign directions such that the person at 'pos' sees exactly 'k' people.
 * 
 * @param n Total number of people (0 to n-1).
 * @param pos The index of the person whose visibility we are checking.
 * @param k The required number of visible people.
 * @returns The number of ways modulo 10^9 + 7.
 */
function solve(n: number, pos: number, k: number): number {
    const MOD = 1000000007;

    // --- Modular Arithmetic Helpers ---

    // Modular exponentiation: (base^exp) % MOD
    const power = (base: number, exp: number): number => {
        let res = 1;
        base %= MOD;
        while (exp > 0) {
            if (exp % 2 === 1) {
                res = (res * base) % MOD;
            }
            base = (base * base) % MOD;
            exp = Math.floor(exp / 2);
        }
        return res;
    };

    // Modular inverse using Fermat's Little Theorem: a^(MOD-2) % MOD
    const modInverse = (n: number): number => {
        return power(n, MOD - 2);
    };

    // --- Precomputation ---

    const MAX_N = n;
    const fact: number[] = new Array(MAX_N + 1);
    const invFact: number[] = new Array(MAX_N + 1);

    fact[0] = 1;
    for (let i = 1; i <= MAX_N; i++) {
        fact[i] = (fact[i - 1] * i) % MOD;
    }

    // Precompute inverse factorials
    invFact[MAX_N] = modInverse(fact[MAX_N]);
    for (let i = MAX_N - 1; i >= 0; i--) {
        invFact[i] = (invFact[i + 1] * (i + 1)) % MOD;
    }

    // Combination function nCr % MOD
    const combinations = (n_val: number, r_val: number): number => {
        if (r_val < 0 || r_val > n_val) {
            return 0;
        }
        if (r_val === 0 || r_val === n_val) {
            return 1;
        }
        // nCr = n! / (r! * (n-r)!)
        let num = fact[n_val];
        let den = (invFact[r_val] * invFact[n_val - r_val]) % MOD;
        return (num * den) % MOD;
    };

    // --- Problem Logic ---

    // L: Number of people to the left (0 to pos-1)
    const L = pos;
    // R: Number of people to the right (pos+1 to n-1)
    const R = n - 1 - pos;

    // We need C_L + C_R = K
    // C_L is the number of people on the left choosing 'L' (out of L people).
    // C_R is the number of people on the right choosing 'R' (out of R people).

    // Determine the bounds for C_L (let i = C_L)

    // 1. i must be non-negative and at most L
    let i_min = 0;
    let i_max = L;

    // 2. C_R = K - i must be non-negative and at most R
    // K - i >= 0  => i <= K
    i_max = Math.min(i_max, k);

    // K - i <= R => i >= K - R
    i_min = Math.max(i_min, k - R);

    let ways_neighbors = 0;

    for (let i = i_min; i <= i_max; i++) {
        const c_l = i;
        const c_r = k - i;

        // Number of ways to choose c_l from L people: C(L, c_l)
        const ways_l = combinations(L, c_l);

        // Number of ways to choose c_r from R people: C(R, c_r)
        const ways_r = combinations(R, c_r);

        // Total ways for this specific split (c_l, c_r)
        let current_ways = (ways_l * ways_r) % MOD;

        ways_neighbors = (ways_neighbors + current_ways) % MOD;
    }

    // The person at 'pos' can choose 'L' or 'R' (2 choices), regardless of K, 
    // as this choice does not affect the count K.
    const total_ways = (ways_neighbors * 2) % MOD;

    return total_ways;
}
